class Solution:
    def toHex(self, num):
        if num == 0:
            return '0'
        if num < 0:
            num += 1 << 32
        digits = '0123456789abcdef'
        out = ''
        while num > 0:
            out = digits[num % 16] + out
            num //= 16
        return out

