class Solution:
    def toHex(self, num):
        if num == 0:
            return '0'
        if num < 0:
            num += 1 << 32
        digits = '0123456789abcdef'
        res = []
        while num:
            res.append(digits[num & 15])
            num >>= 4
        return ''.join(reversed(res))

