var toHex = function(num) {
    if (num === 0) return '0';
    let n = num >>> 0;
    const digits = '0123456789abcdef';
    let res = '';
    while (n > 0) {
        res = digits[n & 15] + res;
        n = n >>> 4;
    }
    return res;
};
